  it("payout of 350.5 → rounded down to 350", () => {
    // dragon sword with high enchantment (≥8): 50% applies.
    // To get 350.5 after deductible: amount/2 - 100 = 350.5 → amount = 901
    const scenario: Scenario = {
      customer: { yearsWithMHPCO: 0 },
