166	  // First insurance surcharge: each item in a quote treated as first insurance.
167	  // Per spec: applies to policy base premium overall (each quote is "a first insurance").
168	  policyModifiers += policyBase * FIRST_INSURANCE_SURCHARGE_PCT;
169	  if (ctx.contractIndex > 0) {
170	    policyModifiers -= policyBase * FOLLOWUP_CONTRACT_DISCOUNT_PCT;
171	  }
172	
173	  const subtotal = policyBase + itemSurcharges + policyModifiers;
174	  const withFee = subtotal + PROCESSING_FEE;
175	  // Round up (in MHPCO's favor for premium)
176	  return Math.ceil(withFee);
