186	export function createPolicy(items: Item[]): Policy {
187	  assertKnownItemTypes(items);
188	  const insuranceSum = items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
189	  const cap = insuranceSum * 2;
190	  return { items, insuranceSum, cap, remainingCap: cap };
