193	function findItemForDamage(policy: Policy, damage: Damage, usedIndices: Set<number>): Item {
194	  if (!isKnownType(damage.itemType)) {
195	    throw new Error(`Unknown item type in damage: ${damage.itemType}`);
196	  }
197	  for (let i = 0; i < policy.items.length; i++) {
198	    if (usedIndices.has(i)) continue;
199	    if (policy.items[i].type === damage.itemType) {
200	      usedIndices.add(i);
201	      return policy.items[i];
202	    }
203	  }
204	  throw new Error(`Damage references item type "${damage.itemType}" not covered by policy (or more damages than items)`);
205	}
