207	function damagePayout(item: Item, damage: Damage): number {
208	  // High-enchantment clause (≥8): 50% reimbursement. Per spec, this wins
209	  // over the dragon-material full-reimbursement clause when both apply.
210	  // Dragon alone reimburses fully (no change). Deductible applies last.
211	  const isHighEnchant =
212	    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
213	  const reimbursable = isHighEnchant ? damage.amount * 0.5 : damage.amount;
214	  return Math.max(0, reimbursable - DEDUCTIBLE);
215	}
