217	export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
218	  // Validate all damages first
219	  for (const d of incident.damages) {
220	    if (d.amount < 0) {
221	      throw new Error(`Damage amount cannot be negative: ${d.amount}`);
222	    }
223	    if (!isKnownType(d.itemType)) {
224	      throw new Error(`Unknown item type in damage: ${d.itemType}`);
225	    }
226	  }
227	
228	  const usedIndices = new Set<number>();
229	  let totalPayout = 0;
230	  for (const damage of incident.damages) {
231	    const item = findItemForDamage(policy, damage, usedIndices);
232	    totalPayout += damagePayout(item, damage);
233	  }
234	
235	  // Apply cap
236	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
237	  // Round down (in MHPCO's favor for payout)
238	  const finalPayout = Math.floor(cappedPayout);
239	  policy.remainingCap -= finalPayout;
240	  return { payout: finalPayout, remainingCap: policy.remainingCap };
241	}
